/**
 * jit-pipeline.js â€” Shared pure data tables and CSS generation pipeline.
 *
 * Imported by both JIT.js (main thread) and jit-worker.js (Web Worker).
 * Contains NO DOM dependencies â€” all browser APIs are injected by callers.
 *
 * Mutable state (colorScale, stepCfg) is managed via setter functions so
 * each consumer (main thread / worker) has independent state.
 */

// ===============================================
//  Mutable state (per-importer)
// ===============================================

let _colorScale = 1;
let _stepCfg = null;
let _ensureStepVarFn = null; // injected: main thread  injects into DOM, worker collects rules

export function setColorScale(v) { _colorScale = v; }
export function getColorScale() { return _colorScale; }
export function setStepConfig(cfg) { _stepCfg = cfg; }
export function getStepConfig() { return _stepCfg; }
export function setEnsureStepVar(fn) { _ensureStepVarFn = fn; }

// ===============================================
//  Type scale
// ===============================================

const PHI = 1.25;
export const TYPE_SCALE = {};
const TYPE_NAMES = ['xs', 'sm', 'base', 'lg', 'xl', '2xl', '3xl', '4xl', '5xl', '6xl'];
const TYPE_BASE = 1;
TYPE_NAMES.forEach((name, i) => {
    const exp = i - 2;
    TYPE_SCALE[name] = +(TYPE_BASE * Math.pow(PHI, exp)).toFixed(4);
});

