// ===============================================
//  9-Step Color System
// ===============================================

export function resolveStep(step) {
    const c = _stepCfg;
    if (!c) return { s: 55, l: 50 };
    const cs = _colorScale;
    const lMax = c.lightBase + (c.lightMax - c.lightBase) * cs;
    const lMin = c.lightBase - (c.lightBase - c.lightMin) * cs;
    const sMax = c.satBase + (c.satMax - c.satBase) * cs;
    const sMin = c.satBase - (c.satBase - c.satMin) * cs;
    const clamp = (v, lo, hi) => Math.max(lo, Math.min(hi, v));

    if (step === c.base) {
        return { s: Math.round(c.satBase + c.satOffset), l: Math.round(c.lightBase + c.lightOffset) };
    }
    if (step < c.base) {
        const t = (c.base - step) / (c.base - 1);
        const tL = Math.pow(t, c.lightCurve);
        const tS = Math.pow(t, c.satCurve);
        const l = clamp(c.lightBase + tL * (lMax - c.lightBase) + c.lightOffset, 0, 100);
        const s = clamp(c.satBase - tS * (c.satBase - sMin) + c.satOffset, 0, 100);
        return { s: Math.round(s), l: Math.round(l) };
    } else {
        const t = (step - c.base) / (c.steps - c.base);
        const tL = Math.pow(t, c.lightCurve);
        const tS = Math.pow(t, c.satCurve);
        const l = clamp(c.lightBase - tL * (c.lightBase - lMin) + c.lightOffset, 0, 100);
        const s = clamp(c.satBase + tS * (sMax - c.satBase) + c.satOffset, 0, 100);
        return { s: Math.round(s), l: Math.round(l) };
    }
}

export function resolveStepDark(step) {
    const c = _stepCfg;
    if (!c) return { s: 55, l: 55 };
    const cs = _colorScale;
    const dLB = 55, dLMax = 15, dLMin = 85;
    const lMax = dLB + (dLMax - dLB) * cs;
    const lMin = dLB - (dLB - dLMin) * cs;
    const sMax = c.satBase + (c.satMax - c.satBase) * cs;
    const sMin = c.satBase - (c.satBase - c.satMin) * cs;
    const clamp = (v, lo, hi) => Math.max(lo, Math.min(hi, v));

    if (step === c.base) {
        return { s: Math.round(c.satBase + c.satOffset), l: Math.round(dLB + c.lightOffset) };
    }
    if (step < c.base) {
        const t = (c.base - step) / (c.base - 1);
        const tL = Math.pow(t, c.lightCurve);
        const tS = Math.pow(t, c.satCurve);
        return {
            s: Math.round(clamp(c.satBase - tS * (c.satBase - sMin) + c.satOffset, 0, 100)),
            l: Math.round(clamp(dLB + tL * (lMax - dLB) + c.lightOffset, 0, 100)),
        };
    } else {
        const t = (step - c.base) / (c.steps - c.base);
        const tL = Math.pow(t, c.lightCurve);
        const tS = Math.pow(t, c.satCurve);
        return {
            s: Math.round(clamp(c.satBase + tS * (sMax - c.satBase) + c.satOffset, 0, 100)),
            l: Math.round(clamp(dLB - tL * (dLB - lMin) + c.lightOffset, 0, 100)),
        };
    }
}

