// ===============================================
//  Pipeline entry points
// ===============================================

export function tryRule(cls, HANDLERS) {
    const stat = STATIC_RULES[cls];
    if (stat !== undefined) return stat;

    const parsed = parseCore(cls, HANDLERS);
    if (parsed) {
        const handler = HANDLERS.get(parsed.category);
        if (handler) {
            const result = handler(parsed.value, parsed.segments, parsed.negate);
            if (result) return result;
        }
    }

    const arb = parseArbitrary(cls);
    if (arb) {
        const gen = ARB[arb.prefix];
        if (gen) return gen(arb.value);
    }

    if (cls.charCodeAt(0) === 91) {
        const raw = cls.match(/^\[(.+?):(.+)\]$/);
        if (raw) return `${raw[1].replace(/_/g, ' ')}: ${raw[2].replace(/_/g, ' ')}`;
    }

    return null;
}

export function generate(cls, HANDLERS) {
    if (cls.charCodeAt(0) === 94 && cls.charCodeAt(1) === 123) return null;

    const sel = '.' + esc(cls);
    const parsed = parsePrefixes(cls);
    if (!parsed) return null;

    const { core, hasPrefix } = parsed;

    const colBp = core.match(/^columns-(sm|md|lg|xl|xxl)-(\d+)$/);
    if (colBp) {
        const n = +colBp[2];
        if (n >= 1 && n <= 12) {
            const colBody = `${sel}{display:grid;grid-template-columns:repeat(${n},1fr)}`;
            return `@container(min-width:${BP[colBp[1]]}px){${colBody}}`;
        }
        return null;
    }

    const body = tryRule(core, HANDLERS);
    if (!body) return null;

    if (!hasPrefix) return `${sel} { ${body} }`;

    return applyPrefixes(cls, sel, body, parsed);
}
