/**
 * css-chunk-emitter.js — Collect, deduplicate, and emit CSS chunks.
 *
 * Organises generated CSS into three priority tiers:
 *   1. **Critical** (layout wrappers, resets) — inlined in <head>
 *   2. **Component** (per-component token CSS) — lazy-loaded with module
 *   3. **Utility** (JIT-generated one-off rules) — appended on demand
 *
 * Each chunk is keyed by a style-hash so identical CSS is never emitted
 * twice (dedup). A manifest object is produced for SSR hydration.
 *
 * Usage (runtime):
 *   const emitter = new CSSChunkEmitter();
 *   emitter.add('critical', 'layout-admin', css);
 *   emitter.add('component', 'Button', css);
 *   emitter.flush();                   // inject all pending into DOM
 *   emitter.manifest();                // { chunks: [...], order: [...] }
 *
 * Usage (build / SSR):
 *   emitter.toCSS('critical');         // concatenated critical CSS string
 *   emitter.manifest();                // JSON-serialisable manifest
 */

import { styleHash } from './style-hash.js';

/** @typedef {'critical'|'component'|'utility'} ChunkTier */

/**
 * @typedef {object} ChunkEntry
 * @property {string}    id    - Logical identifier (e.g. 'Button', 'layout-admin').
 * @property {ChunkTier} tier  - Priority tier.
 * @property {string}    hash  - Style hash of the CSS content.
 * @property {string}    css   - The CSS text.
 * @property {boolean}   flushed - Whether already injected into DOM.
 */

const TIER_ORDER = { critical: 0, component: 1, utility: 2 };

export class CSSChunkEmitter {
    /** @type {Map<string, ChunkEntry>} hash → entry (dedup by content) */
    #chunks = new Map();

    /** @type {Map<string, string>} id → hash (latest per logical id) */
    #idIndex = new Map();

    /** @type {function|null} DOM injector — set via setInjector */
    #injector = null;

    // ── configuration ────────────────────────────────────────────────

    /**
     * Set the DOM injection function.  In the browser this is typically
     * `razyui.injectCSS`; in SSR it can be a no-op or a string collector.
     *
     * @param {(id: string, css: string) => void} fn
     */
    setInjector(fn) {
        this.#injector = fn;
    }

    // ── add / update ─────────────────────────────────────────────────

    /**
     * Add a CSS chunk.  If a chunk with the same hash already exists it
     * is silently deduplicated.  If a chunk with the same `id` but
     * different content exists, it is replaced.
     *
     * @param {ChunkTier} tier
     * @param {string}    id   - Logical identifier.
     * @param {string}    css  - CSS text.
     * @returns {string} The hash of the added chunk.
     */
    add(tier, id, css) {
        const hash = styleHash(css);

        // Same content already tracked?
        if (this.#chunks.has(hash)) {
            this.#idIndex.set(id, hash);
            return hash;
        }

        // Different content for same id → remove old
        const oldHash = this.#idIndex.get(id);
        if (oldHash && oldHash !== hash) {
            this.#chunks.delete(oldHash);
        }

        this.#chunks.set(hash, {
            id,
            tier,
            hash,
            css,
            flushed: false,
        });
        this.#idIndex.set(id, hash);

        return hash;
    }

    // ── queries ──────────────────────────────────────────────────────

    /**
     * Whether a chunk with the given hash (or id) exists.
     *
     * @param {string} hashOrId
     * @returns {boolean}
     */
    has(hashOrId) {
        if (this.#chunks.has(hashOrId)) return true;
        return this.#idIndex.has(hashOrId);
    }

    /**
     * Get all chunks for a given tier, sorted by insertion order.
     *
     * @param {ChunkTier} tier
     * @returns {ChunkEntry[]}
     */
    byTier(tier) {
        const result = [];
        for (const entry of this.#chunks.values()) {
            if (entry.tier === tier) result.push(entry);
        }
        return result;
    }

    /**
     * Concatenate all CSS for a tier into a single string.
     * Useful for SSR critical CSS extraction.
     *
     * @param {ChunkTier} tier
     * @returns {string}
     */
    toCSS(tier) {
        return this.byTier(tier).map(e => e.css).join('\n');
    }

    /** @returns {number} Total chunk count. */
    get size() {
        return this.#chunks.size;
    }

    // ── flush (DOM injection) ────────────────────────────────────────

    /**
     * Inject all un-flushed chunks into the DOM via the configured
     * injector.  Chunks are flushed in tier priority order
     * (critical → component → utility).
     *
     * @returns {number} Number of chunks flushed.
     */
    flush() {
        if (!this.#injector) return 0;

        const pending = [];
        for (const entry of this.#chunks.values()) {
            if (!entry.flushed) pending.push(entry);
        }

        // Sort by tier priority
        pending.sort((a, b) => TIER_ORDER[a.tier] - TIER_ORDER[b.tier]);

        for (const entry of pending) {
            this.#injector(`rui-chunk-${entry.hash}`, entry.css);
            entry.flushed = true;
        }

        return pending.length;
    }

    // ── manifest (SSR) ───────────────────────────────────────────────

    /**
     * Produce a JSON-serialisable manifest for SSR hydration.
     * Contains chunk metadata and the tier-priority load order.
     *
     * @returns {{ chunks: object[], order: string[] }}
     */
    manifest() {
        const chunks = [];
        for (const entry of this.#chunks.values()) {
            chunks.push({
                id: entry.id,
                tier: entry.tier,
                hash: entry.hash,
                size: entry.css.length,
            });
        }

        // Order by tier then insertion
        chunks.sort((a, b) => TIER_ORDER[a.tier] - TIER_ORDER[b.tier]);

        return {
            chunks,
            order: chunks.map(c => c.hash),
        };
    }

    // ── reset ────────────────────────────────────────────────────────

    /** Clear all chunks and id mappings. */
    clear() {
        this.#chunks.clear();
        this.#idIndex.clear();
    }
}
