/**
 * JIT.js - Just-In-Time CSS utility engine for RazyUI v2
 *
 * Scans the DOM for utility class names and injects only the CSS rules
 * needed. A MutationObserver keeps styles in sync as elements are added
 * or changed dynamically.
 *
 * Usage:
 *   const JIT = await razyui.load('JIT');
 *   JIT();                      // scan whole document
 *   JIT({ root: '#app' });     // scan a sub-tree
 *
 * Or auto-start:
 *   <div razyui-jit>            // auto-scanned on DOMContentLoaded
 *
 * Utility patterns:
 *   .text-{size}      .fw-{weight}      .text-{align}
 *   .p-{size}         .px-{n}           .py-{n}       .pt-{n} .pb-{n} .pl-{n} .pr-{n}
 *   .m-{size}         .mx-{n}           .my-{n}       .mt-{n} .mb-{n} .ml-{n} .mr-{n}
 *   .gap-{size}       .gap-x-{size}     .gap-y-{size}
 *   .columns-{n}      .columns-{bp}-{n}
 *   .rounded-{size}   .aspect-{ratio}
 *   .bg-{color}       .fg-{color}       .border-{color}
 *   .badge             .badge-{color}
 *   .btn               .btn-{color}     .btn-outline-{color}  .btn-{size}
 *   .filter-{type}
 *   .hover\:{util}    - any util applied on :hover
 *   .input  .textarea .checkbox .radio .select - form controls
 */

export const stylesheet = null; // no external CSS needed

function normalizeSpaceValue(value) {
    if (value == null) return '';
    if (typeof value === 'number' && Number.isFinite(value)) {
        return value === 0 ? '0' : `${value}px`;
    }
    const text = String(value).trim();
    if (!text) return '';
    return text;
}

function parseStaggerStep(value) {
    if (typeof value === 'number' && Number.isFinite(value)) {
        return { amount: value, unit: 'px' };
    }

    const text = String(value ?? '').trim();
    const m = text.match(/^(-?\d*\.?\d+)([a-z%]*)$/i);
    if (!m) return null;

    return {
        amount: parseFloat(m[1]),
        unit: m[2] || 'px',
    };
}

// -- 9-Step Color System ---------------------
// Reads limits/offsets/curve from CSS custom properties set by _variables.sass.

let colorScale = 1;   // global multiplier (0-1): compresses range toward base
let _stepCfg = null;  // cached config from CSS custom properties

/**
 * Read step configuration from :root CSS custom properties (lazy-cached).
 */
function getStepConfig() {
    if (_stepCfg) return _stepCfg;
    const s = getComputedStyle(document.documentElement);
    const v = (n, d) => { const r = parseFloat(s.getPropertyValue(n)); return Number.isFinite(r) ? r : d; };
    _stepCfg = {
        steps: v('--jit-steps', 9),
        base: v('--jit-base-step', 5),
        lightMax: v('--jit-light-max', 96),
        lightMin: v('--jit-light-min', 10),
        lightBase: v('--jit-light-base', 50),
        lightCurve: v('--jit-light-curve', 1.1),
        lightOffset: v('--jit-light-offset', 0),
        satMax: v('--jit-sat-max', 85),
        satMin: v('--jit-sat-min', 12),
        satBase: v('--jit-sat-base', 55),
        satCurve: v('--jit-sat-curve', 0.9),
        satOffset: v('--jit-sat-offset', 0),
    };
    // Sync to pipeline so shared handlers use fresh config
    _setStepConfig(_stepCfg);
    _setColorScale(colorScale);
    return _stepCfg;
}

/**
 * Sync mutable JIT state to the shared pipeline module.
 * Called once before first class processing (after DOM is ready).
 */
function _syncPipelineState() {
    _setStepConfig(getStepConfig());
    _setColorScale(colorScale);
    _setEnsureStepVar(ensureStepVar);
}

const _stepVarsInjected = new Set();

/**
 * Ensure CSS custom properties for a stepped color exist in all theme scopes.
 * Injects --cs-{name}-{step} variables for light (default) and dark mode.
 *
 * @param {string} colorName - The name of the color (e.g., 'blue', 'red').
 * @param {number} step - The step index (1-9).
 * @param {number} hue - The hue value (0-360).
 */
function ensureStepVar(colorName, step, hue) {
    const key = `${colorName}-${step}`;
    if (_stepVarsInjected.has(key)) return;
    _stepVarsInjected.add(key);
    const { s, l } = resolveStep(step);
    const { s: ds, l: dl } = resolveStepDark(step);
    const sh = getSheet();
    _safeInsert(sh, `:root { --cs-${key}: hsl(${hue},${s}%,${l}%) }`);
    _safeInsert(sh, `[data-theme="dark"] { --cs-${key}: hsl(${hue},${ds}%,${dl}%) }`);
    _safeInsert(sh, `@media(prefers-color-scheme:dark){ :root:not([data-theme="light"]) { --cs-${key}: hsl(${hue},${ds}%,${dl}%) } }`);
}

// -- Color harmony generators ----------------

/**
 * Calculate the complementary hue.
 *
 * @param {number} h - The base hue (0-360).
 * @returns {number} The complementary hue.
 */
function hueComplement(h) { return (h + 180) % 360; }

/**
 * Calculate the triadic hues.
 *
 * @param {number} h - The base hue (0-360).
 * @returns {number[]} An array of two triadic hues.
 */
function hueTriad(h) { return [(h + 120) % 360, (h + 240) % 360]; }

/**
 * Calculate the split-complementary hues.
 *
 * @param {number} h - The base hue (0-360).
 * @returns {number[]} An array of two split-complementary hues.
 */
function hueSplit(h) { return [(h + 150) % 360, (h + 210) % 360]; }

/**
 * Calculate the analogous hues.
 *
 * @param {number} h - The base hue (0-360).
 * @returns {number[]} An array of two analogous hues.
 */
function hueAnalogous(h) { return [(h + 30) % 360, (h - 30 + 360) % 360]; }

// -- 60-30-10 palette state ------------------
let paletteHues = null; // { h60, h30, h10 }

/**
 * Build CSS custom properties for the 60-30-10 palette.
 *
 * @param {string} mode - The theme mode ('light' or 'dark').
 * @returns {string} A string of CSS custom properties.
 */
function buildPaletteVars(mode) {
    if (!paletteHues) return '';
    const { h60, h30, h10 } = paletteHues;
    const isLight = mode === 'light';
    const lines = [
        // 60% - dominant / neutral surface
        `--p-60-bg:hsl(${h60},${isLight ? '15%,98%' : '12%,10%'})`,
        `--p-60-fg:hsl(${h60},${isLight ? '12%,18%' : '10%,90%'})`,
        `--p-60-border:hsl(${h60},${isLight ? '12%,88%' : '10%,20%'})`,
        // 30% - secondary / supporting
        `--p-30-bg:hsl(${h30},${isLight ? '45%,94%' : '35%,16%'})`,
        `--p-30-fg:hsl(${h30},${isLight ? '50%,32%' : '45%,72%'})`,
        `--p-30-border:hsl(${h30},${isLight ? '35%,82%' : '30%,28%'})`,
        // 10% - accent / CTA
        `--p-10-bg:hsl(${h10},${isLight ? '72%,56%' : '60%,52%'})`,
        `--p-10-fg:${isLight ? '#fff' : '#fff'}`,
        `--p-10-border:hsl(${h10},${isLight ? '72%,48%' : '60%,44%'})`,
        `--p-10-hover:hsl(${h10},${isLight ? '72%,48%' : '60%,44%'})`,
        // Complementary
        `--p-comp:hsl(${hueComplement(h60)},${isLight ? '65%,50%' : '55%,52%'})`,
        `--p-comp-bg:hsl(${hueComplement(h60)},${isLight ? '60%,96%' : '40%,16%'})`,
        `--p-comp-fg:hsl(${hueComplement(h60)},${isLight ? '65%,38%' : '55%,70%'})`,
    ];
    return lines.join(';');
}

/**
 * Inject the 60-30-10 palette CSS custom properties into the document head.
 * Replaces any existing palette style element.
 */
function injectPaletteVars() {
    if (!paletteHues) return;
    // Remove old palette style
    const old = document.getElementById('razyui-jit-palette');
    if (old) old.remove();

    const el = razyui.el('style', { id: 'razyui-jit-palette' });
    const lightVars = buildPaletteVars('light');
    const darkVars = buildPaletteVars('dark');
    el[0].textContent = [
        `:root, [data-theme="light"] { ${lightVars} }`,
        `[data-theme="dark"] { ${darkVars} }`,
        `@media(prefers-color-scheme:dark){ :root:not([data-theme="light"]) { ${darkVars} } }`,
    ].join('\n');
    document.head.appendChild(el[0]);
}

// -- WCAG 2.1 contrast utilities -------------

/** Cache for parsed colors - avoids repeated OffscreenCanvas allocations */
const _colorCache = new Map();

/**
 * Parse any CSS color string -> [r, g, b] in 0-255 (cached).
 * Fast-path: hex and named rgb/hsl parsed first (no canvas allocation).
 * Slow-path: OffscreenCanvas for complex color strings (e.g. color-mix()).
 *
 * @param {string} str - The CSS color string to parse.
 * @returns {number[]|null} An array of [r, g, b] values, or null if parsing fails.
 */
function parseColor(str) {
    if (!str || str.startsWith('var(') || str === 'currentColor' || str === 'transparent') return null;
    if (_colorCache.has(str)) return _colorCache.get(str);
    let result = null;
    // Fast-path: hex (most common in design tokens)
    const hex = str.match(/^#([0-9a-f]{3,8})$/i);
    if (hex) {
        let h = hex[1];
        if (h.length === 3) h = h[0] + h[0] + h[1] + h[1] + h[2] + h[2];
        result = [parseInt(h.slice(0, 2), 16), parseInt(h.slice(2, 4), 16), parseInt(h.slice(4, 6), 16)];
    }
    // Fast-path: rgb()/rgba()
    if (!result) {
        const rgbM = str.match(/^rgba?\(\s*(\d{1,3})\s*[,/\s]\s*(\d{1,3})\s*[,/\s]\s*(\d{1,3})/);
        if (rgbM) result = [+rgbM[1], +rgbM[2], +rgbM[3]];
    }
    // Slow-path: OffscreenCanvas for anything else (hsl, color-mix, named colors)
    if (!result && typeof OffscreenCanvas !== 'undefined') {
        try {
            const ctx = new OffscreenCanvas(1, 1).getContext('2d');
            ctx.fillStyle = str;
            ctx.fillRect(0, 0, 1, 1);
            const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
            result = [r, g, b];
        } catch { /* fall through */ }
    }
    _colorCache.set(str, result);
    return result;
}

/**
 * Calculate the sRGB relative luminance (WCAG 2.1).
 *
 * @param {number[]} color - An array of [r, g, b] values (0-255).
 * @returns {number} The relative luminance value.
 */
function luminance([r, g, b]) {
    const [rs, gs, bs] = [r, g, b].map(c => {
        c /= 255;
        return c <= 0.04045 ? c / 12.92 : Math.pow((c + 0.055) / 1.055, 2.4);
    });
    return 0.2126 * rs + 0.7152 * gs + 0.0722 * bs;
}

/**
 * Calculate the WCAG contrast ratio between two [r,g,b] colors.
 *
 * @param {number[]} c1 - The first color as [r, g, b].
 * @param {number[]} c2 - The second color as [r, g, b].
 * @returns {number} The contrast ratio (1 to 21).
 */
function contrastRatio(c1, c2) {
    const l1 = luminance(c1), l2 = luminance(c2);
    const lighter = Math.max(l1, l2), darker = Math.min(l1, l2);
    return (lighter + 0.05) / (darker + 0.05);
}

/**
 * Check if a resolved color pair meets WCAG AA (4.5:1 for normal text).
 *
 * @param {string} fg - The foreground color string.
 * @param {string} bg - The background color string.
 * @returns {boolean} True if the contrast ratio is >= 4.5, or if parsing fails.
 */
function meetsAA(fg, bg) {
    const c1 = parseColor(fg), c2 = parseColor(bg);
    if (!c1 || !c2) return true; // can't check var() - assume OK
    return contrastRatio(c1, c2) >= 4.5;
}

/**
 * Given a background color, return white or dark text for AA compliance.
 *
 * @param {string} bgStr - The background color string.
 * @returns {string|null} The safe text color ('#1a1a2e' or '#f0f0f8'), or null if parsing fails.
 */
function safeTextColor(bgStr) {
    const bg = parseColor(bgStr);
    if (!bg) return null;
    return luminance(bg) > 0.179 ? '#1a1a2e' : '#f0f0f8';
}

