const HANDLERS = new Map();
registerHandlers(HANDLERS);
// Motion handler needs razyui (DOM-dependent) â€” not shared with worker
HANDLERS.set('motion', (val) => {
    const entry = razyui.motion[val];
    if (!entry?.frames) return null;
    razyui.motion.use(val);
    return `animation: rui-${val} ${entry.defaults}`;
});

// Local wrappers that pass HANDLERS to pipeline functions
function parseCore(core) { return _parseCore(core, HANDLERS); }
function applyPrefixes(cls, sel, body, parsed) { return _applyPrefixes(cls, sel, body, parsed); }
function tryRule(cls) { return _tryRule(cls, HANDLERS); }
function generate(cls) { return _generate(cls, HANDLERS); }

/**
 * Generate parent-condition CSS for a ^{mod}: token.
 * Called at defineComponent() time where rootClass is known.
 *
 * @param {string} cls - The raw class token (e.g. '^{is-compact}:hidden')
 * @param {string} rootClass - The component root CSS class (e.g. 'clip-box')
 * @returns {string|string[]|null}
 */
function _generateParentRule(cls, rootClass) {
    const sel = '.' + esc(cls);
    const parsed = parsePrefixes(cls);
    if (!parsed || !parsed.parentModifiers.length) return null;

    const { core, pseudos, medias, modifiers, parentModifiers, selectorMod, hasDark, hasLight, hasBefore, hasAfter } = parsed;

    const body = tryRule(core);
    if (!body) return null;

    const parentSel = '.' + rootClass + parentModifiers.map(m => '.' + m).join('');
    const modSuffix = modifiers.length ? modifiers.map(m => '.' + m).join('') : '';
    const pseudoSuffix = pseudos.join('');

    // Arbitrary selector support in parent rules
    let childSel;
    if (selectorMod) {
        const target = selectorMod.replace(/_/g, ' ');
        childSel = `${sel}${modSuffix} ${target}`.trim() + pseudoSuffix;
    } else {
        childSel = `${sel}${modSuffix}${pseudoSuffix}`;
    }

    let rule = `${parentSel} ${childSel} { ${body} }`;

    for (const bp of medias) {
        rule = `@container(min-width:${BP[bp]}px){${rule}}`;
    }

    if (hasDark) {
        rule = `[data-theme="dark"] ${rule} @media(prefers-color-scheme:dark){:root:not([data-theme="light"]) ${rule}}`;
    }

    if (hasLight) {
        rule = `[data-theme="light"] ${rule} @media(prefers-color-scheme:light){:root:not([data-theme="dark"]) ${rule}}`;
    }

    const rules = [rule];
    if (hasBefore && !core.startsWith('content-')) {
        rules.unshift(`${parentSel} ${sel}::before { content: ''; display: block }`);
    }
    if (hasAfter && !core.startsWith('content-')) {
        rules.unshift(`${parentSel} ${sel}::after { content: ''; display: block }`);
    }

    return rules.length === 1 ? rules[0] : rules;
}

