// ── Token resolver singleton ─────────────────────────────────────────
const _tokenResolver = new TokenResolver();

// ── Dependency graph singleton ───────────────────────────────────────
const _depGraph = new DependencyGraph();

// ── CSS chunk emitter singleton ──────────────────────────────────────
const _cssEmitter = new CSSChunkEmitter();

/**
 * Backward-compatible wrapper that delegates to the TokenResolver
 * singleton.  All existing callers pass this as a plain callback
 * (ref => value) so no context argument is needed.
 *
 * @param {string} ref - Dot-path like 'radius.md', 'spacing.4', 'color.accent'.
 * @returns {string} The resolved CSS value string.
 * @private
 */
function _resolveTokenRef(ref) {
    return _tokenResolver.resolve(ref);
}

// -- TOKEN - Design-token resolver for component modules ------------
// Accessed as razyui.JIT.TOKEN after JIT is loaded.
// Provides resolver functions so component config options can accept
// JIT token names ('sm', 'md', 'lg', 'xl', ...) in addition to raw values.
// --------------------------------------------------------------------

// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
//  Presets â€” compile JIT utilities into direct CSS rules for class names
// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

/** @type {Map<string, string>} className â†’ original JIT utility string */
const _presets = new Map();
/** @type {Array<[string, string]>|null} deferred compilations if sheet not ready */
let _presetQueue = [];

/**
 * Compile a JIT utility string into CSS declarations under a given selector.
 * Each token is resolved via tryRule(); prefixed tokens (hover:, focus:, etc.)
 * go through the full generate() pipeline and are re-targeted to the preset selector.
 *
 * @param {string} presetClass - The preset class name (e.g. 'form-row').
 * @param {string} styles      - Space-separated JIT utility string.
 */
function _compilePreset(presetClass, styles) {
    const sel = '.' + esc(presetClass);
    const baseDecls = [];
    const extraRules = [];

    for (const token of styles.split(/\s+/)) {
        if (!token) continue;

        // Check for prefix (hover:, focus:, sm:, etc.) or state ({is-x}:)
        const hasModifier = token.includes(':');

        if (!hasModifier) {
            // Simple utility â€” extract the declaration body only
            const body = tryRule(token);
            if (body) baseDecls.push(body);
        } else {
            // Prefixed utility â€” generate full rule, then re-target selector
            const rule = generate(token);
            if (!rule) continue;
            const rules = Array.isArray(rule) ? rule : [rule];
            for (const r of rules) {
                // Replace the original escaped selector with the preset selector
                const origSel = '.' + esc(token);
                extraRules.push(r.replace(origSel, sel));
            }
        }
    }

    // Inject the combined base rule
    const s = getSheet();
    if (baseDecls.length) {
        _safeInsert(s, `${sel} { ${baseDecls.join('; ')} }`);
    }
    // Inject extra rules (pseudo/state/media)
    for (const rule of extraRules) {
        _safeInsert(s, rule);
    }
}

/**
 * Compile PartEntity bindings into CSS rules at runtime.
 * Mirrors the build-time compileBindingCSS() from build-css.js.
 *
 * Each binding produces a relational CSS rule:
 *   .source[.when][:pseudo] combinator .target[:targetPseudo] { declarations }
 *
 * @param {PartEntity} part - The source part entity with bindings.
 */
function _compilePresetBindings(part) {
    if (!(part instanceof PartEntity) || !part.bindings.length) return;
    const s = getSheet();

    for (const b of part.bindings) {
        // Source selector: .partClass[.when][:pseudo]
        let sourceSel = '.' + esc(part.className);
        if (b.when) {
            for (const w of b.when.split(/\s+/)) {
                if (w) sourceSel += '.' + w;
            }
        }
        if (b.pseudo) sourceSel += b.pseudo;

        // Target selector
        let targetSel;
        if (b.target instanceof PartEntity) {
            targetSel = '.' + esc(b.target.className) + (b.targetPseudo || '');
        } else {
            const raw = String(b.target);
            targetSel = /^[.#\[]/.test(raw) ? raw : '.' + raw;
            if (b.targetPseudo) targetSel += b.targetPseudo;
        }

        // Full combinator selector
        const comb = b.combinator === ' ' ? ' ' : ` ${b.combinator} `;
        const fullSel = `${sourceSel}${comb}${targetSel}`;

        // Compile each JIT token
        const baseDecls = [];
        const extraRules = [];

        for (const token of b.jit.split(/\s+/)) {
            if (!token) continue;
            const hasModifier = token.includes(':');
            if (!hasModifier) {
                const body = tryRule(token);
                if (body) baseDecls.push(body);
            } else {
                const rule = generate(token);
                if (!rule) continue;
                const ruleArr = Array.isArray(rule) ? rule : [rule];
                for (const r of ruleArr) {
                    const origSel = '.' + esc(token);
                    extraRules.push(r.replace(origSel, fullSel));
                }
            }
        }

        if (baseDecls.length) {
            _safeInsert(s, `${fullSel} { ${baseDecls.join('; ')} }`);
        }
        for (const rule of extraRules) {
            _safeInsert(s, rule);
        }
    }
}

/**
 * Register a preset: compiles the JIT utility string into a direct CSS rule
 * for the given class name. No extra classes are added to elements at runtime â€”
 * the class itself carries all the styles.
 *
 * @param {string|Object<string,string>} name - Class name, or a map of { className: jitStyles }.
 * @param {string} [styles] - Space-separated JIT utility string (when name is a string).
 */
JIT.setPreset = function (name, styles) {
    const register = (k, v) => {
        // Unwrap PartEntity: extract jit string + compile bindings
        let jit = v;
        let part = null;
        if (v instanceof PartEntity) {
            jit = v.jit || '';
            part = v;
        }
        if (typeof jit !== 'string' || !jit) {
            // Even without jit string, bindings may still need compiling
            if (part && part.bindings.length) {
                if (_presetQueue) {
                    _presetQueue.push([k, '', part]);
                } else {
                    _compilePresetBindings(part);
                }
            }
            return;
        }
        _presets.set(k, jit);
        if (_presetQueue) {
            _presetQueue.push([k, jit, part]);
        } else {
            _compilePreset(k, jit);
            if (part) _compilePresetBindings(part);
        }
    };
    if (typeof name === 'object' && name !== null) {
        for (const [k, v] of Object.entries(name)) {
            if ((typeof v === 'string' && v) || v instanceof PartEntity) register(k, v);
        }
    } else if (typeof name === 'string' && (typeof styles === 'string' || styles instanceof PartEntity)) {
        register(name, styles);
    }
};

JIT.getPreset = function (name) {
    return _presets.get(name) ?? null;
};

/**
 * Register per-preset JIT overrides for a component (same part-map shape as `razyui.styling()`).
 * Use with a matching `preset` attribute / config on the component instance.
 *
 * @param {string|Object<string, Object<string, *>>} compoundOrMap - `'Input.myPreset'` or `{ 'Input.myPreset': { field: … } }`
 * @param {Object<string, *>} [styles] - Part name → CSS object or plain object of JIT-able props (when compound is a string)
 *
 * @example
 *   JIT.setComponentPreset('Input.dense', {
 *     wrapper: { height: '2rem', padding: '0 0.5rem' },
 *     field: { 'font-size': '0.75rem' },
 *   });
 *   // <rui-input preset="dense"></rui-input>
 */
JIT.setComponentPreset = function (compoundOrMap, styles) {
    const registerOne = (compound, partMap) => {
        const parsed = _parseComponentPresetCompound(compound);
        if (!parsed || !parsed.preset) return;
        if (!razyui.isPO(partMap)) return;

        const normalized = {};
        razyui.each(partMap, (partStyles, partName) => {
            if (typeof partStyles === 'string') {
                const t = partStyles.trim();
                if (t) normalized[_normalizeKey(partName)] = t;
                return;
            }
            if (!razyui.isPO(partStyles)) return;
            const jitClasses = JIT.cssObjectClasses(partStyles) || [];
            normalized[_normalizeKey(partName)] = jitClasses.join(' ');
        });
        const regKey = _componentPresetRegistryKey(parsed.component, parsed.preset);
        _componentPresetRegistry.set(regKey, normalized);
    };

    if (typeof compoundOrMap === 'object' && compoundOrMap !== null && !Array.isArray(compoundOrMap)) {
        for (const [k, v] of Object.entries(compoundOrMap)) {
            registerOne(k, v);
        }
    } else if (typeof compoundOrMap === 'string' && razyui.isPO(styles)) {
        registerOne(compoundOrMap, styles);
    }
};

/**
 * Read resolved part → JIT class map for a component preset (for debugging / introspection).
 *
 * @param {string} compound - `'ComponentName.presetId'`
 * @returns {Object<string, string>|null}
 */
JIT.getComponentPreset = function (compound) {
    const parsed = _parseComponentPresetCompound(compound);
    if (!parsed) return null;
    const regKey = _componentPresetRegistryKey(parsed.component, parsed.preset);
    const out = _componentPresetRegistry.get(regKey);
    return out ? { ...out } : null;
};

