/**
 * token-resolver.js — Design-token resolution with scoped layers.
 *
 * Replaces the monolithic _resolveTokenRef() switch/case in JIT.js with
 * a class that supports 4-layer scoping:
 *   Global → Layout → Component → Instance
 *
 * Phase 1 delivers Global + Layout scopes with full backward compat.
 * Cross-component references (Phase 2) are stubbed but not active.
 */

import { SPACE, RADIUS } from './jit-pipeline.js';

// ── Font size sub-table (matches original _resolveTokenRef) ──────────
const FONT_SIZES = {
    'size-xs': '0.75rem',
    'size-sm': '0.85rem',
    'size-md': '1rem',
    'size-lg': '1.125rem',
    'size-xl': '1.25rem',
};

// ── Per-category resolver functions ──────────────────────────────────
// Each returns a CSS value string for the given key, or the raw key
// if nothing matches.

const CATEGORY_RESOLVERS = {
    color(key) {
        return `var(--rui-${key})`;
    },

    spacing(key) {
        return SPACE[key] ?? key;
    },

    radius(key) {
        return RADIUS[key] ?? key;
    },

    shadow(key) {
        if (key === 'none') return 'none';
        if (key === 'md') return 'var(--rui-shadow)';
        return `var(--rui-shadow-${key})`;
    },

    font(key) {
        if (key === 'family' || key === 'stack') return 'inherit';
        if (key === 'mono') return 'var(--rui-font-mono)';
        return FONT_SIZES[key] ?? key;
    },

    'z-index'(key) {
        return `var(--rui-z-${key})`;
    },

    transition(key) {
        return `var(--rui-transition-${key})`;
    },
};

// =====================================================================

export class TokenResolver {
    /** @type {Map<string, object>} layoutId → { token: value } */
    #layouts = new Map();

    /** @type {Map<string, object>} componentName → def (for cross-ref) */
    #components = new Map();

    // ── resolve ──────────────────────────────────────────────────────
    /**
     * Resolve a dot-path token reference to a CSS value.
     *
     * Without `context` this behaves identically to the legacy
     * `_resolveTokenRef()` function — existing callers can pass this
     * method (bound) as a drop-in replacement.
     *
     * @param {string}  ref             - e.g. 'color.text', 'spacing.4', 'layout.sidebar-width'
     * @param {object}  [context]       - Optional scope context.
     * @param {string}  [context.layoutId] - Active layout id for `layout.*` refs.
     * @returns {string} Resolved CSS value.
     */
    resolve(ref, context) {
        const dotIdx = ref.indexOf('.');
        if (dotIdx === -1) return ref;

        const category = ref.slice(0, dotIdx);
        const key = ref.slice(dotIdx + 1);

        // Layout-scoped tokens
        if (category === 'layout') {
            return this.#resolveLayout(key, context);
        }

        // Standard global category
        const handler = CATEGORY_RESOLVERS[category];
        if (handler) return handler(key);

        // Unrecognised category — return ref as-is (safe default)
        return ref;
    }

    // ── Layout tokens ────────────────────────────────────────────────
    /**
     * Register a named layout with its token map.
     *
     * @param {string} id     - Layout identifier (e.g. 'admin').
     * @param {object} tokens - Key/value pairs, e.g. { 'sidebar-width': '16rem' }.
     */
    registerLayout(id, tokens) {
        this.#layouts.set(id, { ...tokens });
    }

    /**
     * Resolve a layout token key.  When a layoutId is provided via
     * context the resolver checks the layout map first, falling back
     * to a CSS custom-property reference so runtime overrides still
     * work.
     *
     * @param {string} key
     * @param {object} [context]
     * @returns {string}
     */
    #resolveLayout(key, context) {
        const id = context?.layoutId;
        if (id) {
            const layoutTokens = this.#layouts.get(id);
            if (layoutTokens && key in layoutTokens) {
                return layoutTokens[key];
            }
        }
        // Fallback: emit a custom-property ref so the value can be set
        // at runtime via CSS on a layout wrapper element.
        return id
            ? `var(--layout-${id}-${key})`
            : `var(--layout-${key})`;
    }

    // ── Component registry (Phase 2 prep) ────────────────────────────
    /**
     * Record a component definition so other components can reference
     * its tokens via `ComponentName.tokenKey`.
     *
     * @param {string} name - PascalCase component name.
     * @param {object} def  - The component definition object.
     */
    registerComponent(name, def) {
        this.#components.set(name, def);
    }
}
