/**
 * dependency-graph.js — Component dependency graph with topological sort.
 *
 * Tracks which components are required by a layout or by other components,
 * then produces a safe load & compile order.
 *
 * Usage:
 *   const graph = new DependencyGraph();
 *   graph.add('Modal',   ['Overlay', 'Button']);
 *   graph.add('Overlay', []);
 *   graph.add('Button',  []);
 *   graph.sorted();        // ['Overlay', 'Button', 'Modal']
 *   graph.depsOf('Modal'); // Set { 'Overlay', 'Button' }
 */

export class DependencyGraph {
    /** @type {Map<string, Set<string>>} node → direct dependencies */
    #edges = new Map();

    // ── mutators ─────────────────────────────────────────────────────

    /**
     * Register a node with its direct dependencies.
     * Can be called multiple times — deps are merged.
     *
     * @param {string}   name - Component / layout node name.
     * @param {string[]} [deps=[]] - Names this node depends on.
     */
    add(name, deps = []) {
        if (!this.#edges.has(name)) {
            this.#edges.set(name, new Set());
        }
        const set = this.#edges.get(name);
        for (const d of deps) {
            set.add(d);
            // Ensure dep node exists even if not explicitly added
            if (!this.#edges.has(d)) {
                this.#edges.set(d, new Set());
            }
        }
    }

    /**
     * Remove a node and all edges pointing to it.
     *
     * @param {string} name
     */
    remove(name) {
        this.#edges.delete(name);
        for (const set of this.#edges.values()) {
            set.delete(name);
        }
    }

    /** Remove all nodes and edges. */
    clear() {
        this.#edges.clear();
    }

    // ── queries ──────────────────────────────────────────────────────

    /**
     * Direct dependencies of `name`.
     *
     * @param {string} name
     * @returns {Set<string>}
     */
    depsOf(name) {
        return new Set(this.#edges.get(name) ?? []);
    }

    /**
     * Transitive (deep) dependencies of `name`, NOT including `name` itself.
     *
     * @param {string} name
     * @returns {Set<string>}
     */
    allDepsOf(name) {
        const result = new Set();
        const stack = [...(this.#edges.get(name) ?? [])];
        while (stack.length) {
            const n = stack.pop();
            if (result.has(n)) continue;
            result.add(n);
            const children = this.#edges.get(n);
            if (children) {
                for (const c of children) {
                    if (!result.has(c)) stack.push(c);
                }
            }
        }
        return result;
    }

    /**
     * All registered node names.
     *
     * @returns {string[]}
     */
    nodes() {
        return [...this.#edges.keys()];
    }

    /** @returns {number} */
    get size() {
        return this.#edges.size;
    }

    /**
     * Check whether the node exists in the graph.
     *
     * @param {string} name
     * @returns {boolean}
     */
    has(name) {
        return this.#edges.has(name);
    }

    // ── topological sort (Kahn's algorithm) ──────────────────────────

    /**
     * Return nodes in dependency-safe order (leaves first).
     * Throws if the graph has a cycle.
     *
     * @returns {string[]} Topologically sorted node names.
     */
    sorted() {
        // in-degree map
        const inDeg = new Map();
        for (const name of this.#edges.keys()) {
            if (!inDeg.has(name)) inDeg.set(name, 0);
        }
        for (const [, deps] of this.#edges) {
            for (const d of deps) {
                inDeg.set(d, (inDeg.get(d) ?? 0));
            }
        }
        // Count incoming edges (reverse direction: dep → dependent)
        for (const [name, deps] of this.#edges) {
            for (const _d of deps) {
                // name depends on _d → _d has no extra in-edge,
                // but name has in-degree from _d
                // Actually for topo sort: edge goes dep → name
            }
        }

        // Recompute properly: for each (name → deps), edge is dep→name
        // in-degree of name = number of deps it has
        const inDegree = new Map();
        for (const name of this.#edges.keys()) {
            inDegree.set(name, 0);
        }
        for (const [name, deps] of this.#edges) {
            inDegree.set(name, deps.size);
        }

        const queue = [];
        for (const [name, deg] of inDegree) {
            if (deg === 0) queue.push(name);
        }

        // reverse adjacency: for each (name → deps), dep is a prereq of name
        // so in reversed view: dep → [name, ...]
        const dependents = new Map();
        for (const [name, deps] of this.#edges) {
            for (const d of deps) {
                if (!dependents.has(d)) dependents.set(d, []);
                dependents.get(d).push(name);
            }
        }

        const result = [];
        while (queue.length) {
            const n = queue.shift();
            result.push(n);
            const children = dependents.get(n);
            if (children) {
                for (const child of children) {
                    const newDeg = inDegree.get(child) - 1;
                    inDegree.set(child, newDeg);
                    if (newDeg === 0) queue.push(child);
                }
            }
        }

        if (result.length !== this.#edges.size) {
            const remaining = this.nodes().filter(n => !result.includes(n));
            throw new Error(
                `DependencyGraph: cycle detected involving: ${remaining.join(', ')}`
            );
        }

        return result;
    }

    // ── subset extraction ────────────────────────────────────────────

    /**
     * Build a new DependencyGraph containing only `names` and their
     * transitive dependencies.
     *
     * @param {string[]} names - Root nodes to include.
     * @returns {DependencyGraph}
     */
    subgraph(names) {
        const needed = new Set();
        for (const name of names) {
            needed.add(name);
            for (const d of this.allDepsOf(name)) {
                needed.add(d);
            }
        }
        const sub = new DependencyGraph();
        for (const name of needed) {
            const deps = this.#edges.get(name);
            sub.add(name, deps ? [...deps] : []);
        }
        return sub;
    }
}
